logger = logging.getLogger(__name__)

class SQSWorker:
    def __init__(self, queue_url: str, region_name: str = None, 
                 max_workers: int = 10, visibility_timeout: int = 300):
        self.queue_url = queue_url
        self.region_name = region_name or os.getenv('AWS_REGION', 'us-east-1')
        self.max_workers = max_workers
        self.visibility_timeout = visibility_timeout
        self.sqs_client = None
        self.running = False
        self.message_handlers = {}
        self._setup_signal_handlers()
        
    def _setup_signal_handlers(self):
        """Setup signal handlers for graceful shutdown"""
        signal.signal(signal.SIGTERM, self._shutdown_handler)
        signal.signal(signal.SIGINT, self._shutdown_handler)
        
    def _shutdown_handler(self, signum, frame):
        """Handle shutdown signals"""
        logger.info(f"Received signal {signum}, shutting down gracefully...")
        self.running = False
        
    def _validate_message(self, message: Dict[str, Any]) -> bool:
        """Validate message structure"""
        if not isinstance(message, dict):
            logger.warning("Message is not a dictionary")
            return False
            
        if 'type' not in message:
            logger.warning("Message missing 'type' field")
            return False
            
        if 'data' not in message:
            logger.warning("Message missing 'data' field")
            return False
            
        return True
        
    def _execute_action(self, message_type: str, data: Dict[str, Any]) -> bool:
        """Execute action based on message type"""
        try:
            if message_type not in self.message_handlers:
                logger.warning(f"No handler for message type: {message_type}")
                return False
                
            handler = self.message_handlers[message_type]
            result = handler(data)
            logger.info(f"Successfully processed message type: {message_type}")
            return True
            
        except Exception as e:
            logger.error(f"Error processing message type {message_type}: {str(e)}")
            return False
            
    def register_handler(self, message_type: str, handler_func):
        """Register a handler function for a specific message type"""
        if not callable(handler_func):
            raise ValueError("Handler must be callable")
            
        self.message_handlers[message_type] = handler_func
        
    def _setup_sqs_client(self):
        """Setup SQS client with proper credentials"""
        try:
            if 'AWS_ACCESS_KEY_ID' in os.environ and 'AWS_SECRET_ACCESS_KEY' in os.environ:
                self.sqs_client = boto3.client(
                    'sqs',
                    region_name=self.region_name,
                    aws_access_key_id=os.environ['AWS_ACCESS_KEY_ID'],
                    aws_secret_access_key=os.environ['AWS_SECRET_ACCESS_KEY']
                )
            else:
                self.sqs_client = boto3.client('sqs', region_name=self.region_name)
                
        except NoCredentialsError:
            logger.error("AWS credentials not found")
            raise
        except Exception as e:
            logger.error(f"Failed to create SQS client: {str(e)}")
            raise
            
    def _process_message(self, message: Dict[str, Any]) -> bool:
        """Process a single message"""
        try:
            # Validate message
            if not self._validate_message(message):
                logger.warning("Invalid message format")
                return False
                
            message_type = message['type']
            data = message['data']
            
            # Execute action
            success = self._execute_action(message_type, data)
            
            return success
            
        except Exception as e:
            logger.error(f"Error processing message: {str(e)}")
            return False
            
    def _delete_message(self, receipt_handle: str) -> bool:
        """Delete message from queue"""
        try:
            self.sqs_client.delete_message(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle
            )
            return True
        except ClientError as e:
            logger.error(f"Failed to delete message: {str(e)}")
            return False
            
    def _receive_messages(self, max_messages: int = 10) -> list:
        """Receive messages from SQS queue"""
        try:
            response = self.sqs_client.receive_message(
                QueueUrl=self.queue_url,
                MaxNumberOfMessages=max_messages,
                VisibilityTimeout=self.visibility_timeout,
                WaitTimeSeconds=20
            )
            
            return response.get('Messages', [])
            
        except ClientError as e:
            logger.error(f"Failed to receive messages: {str(e)}")
            return []
            
    def start(self):
        """Start the worker"""
        logger.info("Starting SQS worker...")
        
        try:
            self._setup_sqs_client()
            self.running = True
            
            while self.running:
                messages = self._receive_messages(max_messages=10)
                
                if not messages:
                    continue
                    
                for message in messages:
                    receipt_handle = message['ReceiptHandle']
                    message_body = message['Body']
                    
                    try:
                        # Parse JSON message
                        parsed_message = json.loads(message_body)
                        
                        # Process message
                        success = self._process_message(parsed_message)
                        
                        # Delete message if successful
                        if success:
                            self._delete_message(receipt_handle)
                        else:
                            logger.warning("Message processing failed, keeping in queue")
                            
                    except json.JSONDecodeError:
                        logger.error("Invalid JSON in message body")
                        # Delete invalid message
                        self._delete_message(receipt_handle)
                    except Exception as e:
                        logger.error(f"Unexpected error processing message: {str(e)}")
                        # Delete message on unexpected error
                        self._delete_message(receipt_handle)
                        
        except KeyboardInterrupt:
            logger.info("Keyboard interrupt received")
        except Exception as e:
            logger.error(f"Worker error: {str(e)}")
        finally:
            logger.info("Worker stopped")
            
    def stop(self):
        """Stop the worker"""
        self.running = False

